ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  customerId: attributes.uriParams.customerId,
  features: {
    historicalUsage: vars.historicalData map {
      date: $.usage_date as String,
      kwh: $.kwh_used,
      cost: $.cost,
      peakDemand: $.peak_demand,
      temperature: $.temperature,
      dayOfWeek: $.day_of_week,
      month: $.month,
      season: $.season
    },
    customerProfile: {
      homeType: vars.historicalData[0].home_type,
      homeSizeSqft: vars.historicalData[0].home_size_sqft,
      occupancyCount: vars.historicalData[0].occupancy_count
    }
  },
  predictionTypes: ["usage", "cost", "peak_usage_days", "savings_opportunities"]
}

%dw 2.0
output application/json
import * from dw::core::Arrays

fun calculateWeatherImpact(forecastTemp, historicalData) = 
  historicalData filter ($.temperature > (forecastTemp + 5) or $.temperature < (forecastTemp - 5))
  then avg($.kwh_used) - avg(historicalData.kwh_used)
  else 0

fun identifyPeakDays(forecast, predictions) = 
  forecast.daily filter ($.high_temp > 85 or $.low_temp < 45)
  then $.date
  else []

fun generateSavingsOpportunities(customerData, benchmarks) = [
  {
    category: "Time of Use",
    potentialSavings: if (customerData.peakUsageRatio > 0.4) 25 + (customerData.peakUsageRatio * 50) else 0,
    recommendation: "Shift high-energy activities to off-peak hours (9 PM - 6 AM)",
    difficulty: "Easy"
  },
  {
    category: "HVAC Optimization",
    potentialSavings: if (customerData.hvacUsage > benchmarks.hvacAvg * 1.2) 35 + ((customerData.hvacUsage - benchmarks.hvacAvg) / benchmarks.hvacAvg * 100) else 0,
    recommendation: "Install programmable thermostat and improve insulation",
    difficulty: "Medium"
  },
  {
    category: "Appliance Efficiency",
    potentialSavings: if (customerData.applianceAge > 10) 20 + (customerData.applianceAge * 2) else 0,
    recommendation: "Replace old appliances with ENERGY STAR certified models",
    difficulty: "Hard"
  },
  {
    category: "Solar Installation",
    potentialSavings: if (customerData.roofSuitability > 0.7 and customerData.avgMonthlyBill > 150) customerData.avgMonthlyBill * 0.8 else 0,
    recommendation: "Consider rooftop solar installation with net metering",
    difficulty: "Hard"
  }
] filter $.potentialSavings > 0

---
{
  customerId: attributes.uriParams.customerId,
  predictions: {
    nextMonthUsage: vars.mlResults.predictions.usage.nextMonth + calculateWeatherImpact(avg(vars.weatherForecast.daily.high_temp), vars.historicalData),
    nextMonthCost: vars.mlResults.predictions.cost.nextMonth * (1 + calculateWeatherImpact(avg(vars.weatherForecast.daily.high_temp), vars.historicalData) * 0.15),
    peakUsageDays: identifyPeakDays(vars.weatherForecast, vars.mlResults.predictions) as Array<Date>,
    savingsOpportunities: generateSavingsOpportunities({
      peakUsageRatio: avg(vars.historicalData filter ($.peak_demand > 0) then $.peak_demand else [0]) / avg(vars.historicalData.kwh_used),
      hvacUsage: avg(vars.historicalData filter ($.temperature > 80 or $.temperature < 60) then $.kwh_used else vars.historicalData.kwh_used),
      applianceAge: 8, // This would come from customer profile
      roofSuitability: 0.85, // This would come from solar analysis service
      avgMonthlyBill: avg(vars.historicalData.cost) * 30
    }, {
      hvacAvg: 450 // Industry benchmark
    })
  },
  insights: {
    usageTrend: if (vars.mlResults.predictions.usage.trend > 0) "increasing" else "decreasing",
    efficiencyScore: min([100, max([0, 100 - (vars.mlResults.predictions.usage.nextMonth / vars.mlResults.benchmarks.similar_homes_avg - 1) * 100])]),
    seasonalPattern: vars.mlResults.patterns.seasonal,
    recommendations: [
      "Your usage is projected to " ++ (if (vars.mlResults.predictions.usage.trend > 0) "increase" else "decrease") ++ " by " ++ abs(vars.mlResults.predictions.usage.trend) ++ "% next month",
      "You rank in the " ++ (100 - min([100, max([0, 100 - (vars.mlResults.predictions.usage.nextMonth / vars.mlResults.benchmarks.similar_homes_avg - 1) * 100])])) ++ "th percentile for energy efficiency in your area"
    ]
  }
}

db:select.db:input-parameters:
#[{
        homeType: vars.customerPattern.home_type,
        sizeLower: vars.customerPattern.home_size_sqft * 0.8,
        sizeUpper: vars.customerPattern.home_size_sqft * 1.2
      }]

