%dw 2.0
output application/json

fun getSeasonalTips(season) = 
  season match {
    case "summer" -> [
      {
        tip: "Set your air conditioner to 78°F when home and 85°F when away to save up to 10% on cooling costs",
        category: "HVAC",
        difficulty: "easy",
        potentialSavings: "10-15%"
      },
      {
        tip: "Use ceiling fans to circulate air and feel 4°F cooler, allowing you to raise the thermostat setting",
        category: "HVAC",
        difficulty: "easy", 
        potentialSavings: "5-8%"
      },
      {
        tip: "Close curtains and blinds during the day to block out heat from the sun",
        category: "Cooling",
        difficulty: "easy",
        potentialSavings: "3-5%"
      },
      {
        tip: "Schedule high-energy activities like laundry and dishwashing for early morning or late evening",
        category: "Scheduling",
        difficulty: "easy",
        potentialSavings: "8-12%"
      }
    ]
    case "winter" -> [
      {
        tip: "Lower your thermostat to 68°F during the day and 60-65°F at night to save on heating costs",
        category: "HVAC",
        difficulty: "easy",
        potentialSavings: "10-15%"
      },
      {
        tip: "Seal air leaks around windows and doors with weather stripping or caulk",
        category: "Insulation",
        difficulty: "medium",
        potentialSavings: "15-20%"
      },
      {
        tip: "Use a programmable thermostat to automatically adjust temperature when you're away",
        category: "HVAC",
        difficulty: "medium",
        potentialSavings: "8-12%"
      },
      {
        tip: "Open curtains on sunny days to let natural heat in, and close them at night for insulation",
        category: "Heating",
        difficulty: "easy",
        potentialSavings: "5-8%"
      }
    ]
    case "spring" -> [
      {
        tip: "Schedule HVAC maintenance to ensure efficient operation for the coming summer",
        category: "HVAC",
        difficulty: "easy",
        potentialSavings: "5-10%"
      },
      {
        tip: "Clean or replace air filters for better airflow and efficiency",
        category: "HVAC", 
        difficulty: "easy",
        potentialSavings: "5-8%"
      },
      {
        tip: "Take advantage of mild weather to air dry clothes instead of using the dryer",
        category: "Appliances",
        difficulty: "easy",
        potentialSavings: "8-15%"
      }
    ]
    case "fall" -> [
      {
        tip: "Prepare for winter by sealing air leaks and adding insulation",
        category: "Insulation",
        difficulty: "medium", 
        potentialSavings: "15-25%"
      },
      {
        tip: "Service your heating system before cold weather arrives",
        category: "HVAC",
        difficulty: "easy",
        potentialSavings: "8-12%"
      },
      {
        tip: "Use natural sunlight for heating by opening south-facing curtains during the day",
        category: "Heating",
        difficulty: "easy",
        potentialSavings: "3-5%"
      }
    ]
    else -> []
  }

---
getSeasonalTips(vars.season default "general")

